import { setup, assign } from 'xstate';

type AuctionContext = {
  windowMs: number;
  highBid: number;
  winner: string | null;
};

type AuctionEvent =
  | { type: 'BID'; amount: number; bidder: string }
  | { type: 'EXTEND'; ms: number };

export const auctionMachine = setup({
  types: {
    context: {} as AuctionContext,
    events: {} as AuctionEvent,
  },
  actions: {
    acceptBid: assign({
      highBid: ({ event }) =>
        event.type === 'BID' ? event.amount : 0,
      winner: ({ event }) =>
        event.type === 'BID' ? event.bidder : null,
    }),
    extendWindow: assign({
      windowMs: ({ context, event }) =>
        event.type === 'EXTEND' ? context.windowMs + event.ms : context.windowMs,
    }),
  },
  delays: {
    closeWindow: ({ context }) => context.windowMs,
  },
}).createMachine({
  id: 'auction',
  initial: 'open',
  context: { windowMs: 30000, highBid: 0, winner: null },
  states: {
    open: {
      after: {
        closeWindow: { target: 'closed' },
      },
      on: {
        BID: {
          target: 'open',
          reenter: true,
          actions: 'acceptBid',
        },
        EXTEND: { actions: 'extendWindow' },
      },
    },
    closed: { type: 'final' },
  },
});
