In v5 an `after` block attaches delayed transitions to a state. Keys can be either a literal millisecond number or a name referring to `setup.delays`. The timer starts when the state is entered and is cancelled when the state is exited (whether by another event or by the timer itself firing). Named delays can read `context` so each instance can time itself individually.

```ts
import { setup, assign } from 'xstate';

type ToastContext = { visibleFor: number };
type ToastEvent = { type: 'SHOW' } | { type: 'DISMISS' };

export const toastMachine = setup({
  types: {
    context: {} as ToastContext,
    events: {} as ToastEvent,
  },
  delays: {
    autoHide: ({ context }) => context.visibleFor,
  },
}).createMachine({
  id: 'toast',
  initial: 'hidden',
  context: { visibleFor: 4000 },
  states: {
    hidden: {
      on: { SHOW: { target: 'visible' } },
    },
    visible: {
      after: {
        autoHide: { target: 'hidden' },
      },
      on: {
        DISMISS: { target: 'hidden' },
      },
    },
  },
});
```

